134	static std::pair<int, int> get_expected_segs_to_target(RRNodeId inode, RRNodeId target_node) {
135	    /* Returns the number of segments the same type as inode that will be needed *
136	     * to reach target_node (not including inode) in each direction (the same    *
137	     * direction (horizontal or vertical) as inode and the orthogonal direction).*/
138	    auto& device_ctx = g_vpr_ctx.device();
139	    const auto& rr_graph = device_ctx.rr_graph;
140	
141	    int num_segs_ortho_dir;
142	    int num_segs_same_dir;
143	
144	    int no_need_to_pass_by_clb;
145	    float ylow, yhigh, xlow, xhigh;
146	
147	    int target_x = rr_graph.node_xlow(target_node);
148	    int target_y = rr_graph.node_ylow(target_node);
149	
150	    RRIndexedDataId cost_index = rr_graph.node_cost_index(inode);
151	    float inv_length = device_ctx.rr_indexed_data[cost_index].inv_length;
152	    int ortho_cost_index = device_ctx.rr_indexed_data[cost_index].ortho_cost_index;
153	    float ortho_inv_length = device_ctx.rr_indexed_data[RRIndexedDataId(ortho_cost_index)].inv_length;
154	    e_rr_type rr_type = rr_graph.node_type(inode);
155	
156	    if (rr_type == e_rr_type::CHANX) {
157	        ylow = rr_graph.node_ylow(inode);
158	        xhigh = rr_graph.node_xhigh(inode);
159	        xlow = rr_graph.node_xlow(inode);
160	
161	        /* Count vertical (orthogonal to inode) segs first. */
162	
163	        if (ylow > target_y) { /* Coming from a row above target? */
164	            num_segs_ortho_dir = round_up((ylow - target_y + 1.) * ortho_inv_length);
165	            no_need_to_pass_by_clb = 1;
166	        } else if (ylow < target_y - 1) { /* Below the CLB bottom? */
167	            num_segs_ortho_dir = round_up((target_y - ylow) * ortho_inv_length);
168	            no_need_to_pass_by_clb = 1;
169	        } else { /* In a row that passes by target CLB */
170	            num_segs_ortho_dir = 0;
171	            no_need_to_pass_by_clb = 0;
172	        }
173	
174	        /* Now count horizontal (same dir. as inode) segs. */
175	
176	        if (xlow > target_x + no_need_to_pass_by_clb) {
177	            num_segs_same_dir = round_up((xlow - no_need_to_pass_by_clb - target_x) * inv_length);
178	        } else if (xhigh < target_x - no_need_to_pass_by_clb) {
179	            num_segs_same_dir = round_up((target_x - no_need_to_pass_by_clb - xhigh) * inv_length);
180	        } else {
181	            num_segs_same_dir = 0;
182	        }
183	    } else { /* inode is a CHANY */
184	        ylow = rr_graph.node_ylow(inode);
185	        yhigh = rr_graph.node_yhigh(inode);
186	        xlow = rr_graph.node_xlow(inode);
187	
188	        /* Count horizontal (orthogonal to inode) segs first. */
189	
190	        if (xlow > target_x) { /* Coming from a column right of target? */
191	            num_segs_ortho_dir = round_up((xlow - target_x + 1.) * ortho_inv_length);
192	            no_need_to_pass_by_clb = 1;
193	        } else if (xlow < target_x - 1) { /* Left of and not adjacent to the CLB? */
194	            num_segs_ortho_dir = round_up((target_x - xlow) * ortho_inv_length);
195	            no_need_to_pass_by_clb = 1;
196	        } else { /* In a column that passes by target CLB */
197	            num_segs_ortho_dir = 0;
198	            no_need_to_pass_by_clb = 0;
199	        }
200	
201	        /* Now count vertical (same dir. as inode) segs. */
202	
203	        if (ylow > target_y + no_need_to_pass_by_clb) {
204	            num_segs_same_dir = round_up((ylow - no_need_to_pass_by_clb - target_y) * inv_length);
205	        } else if (yhigh < target_y - no_need_to_pass_by_clb) {
206	            num_segs_same_dir = round_up((target_y - no_need_to_pass_by_clb - yhigh) * inv_length);
207	        } else {
208	            num_segs_same_dir = 0;
209	        }
210	    }
211	
212	    return {num_segs_same_dir, num_segs_ortho_dir};
213	}
