32	 * the list at each coordinate is later boiled down to a single representative cost entry to be stored in the final cost map */
33	typedef vtr::NdMatrix<Expansion_Cost_Entry, 3> t_routing_cost_map; //[0..num_layers][0..device_ctx.grid.width()-1][0..device_ctx.grid.height()-1]
