66	/* when a list of delay/congestion entries at a coordinate in Cost_Entry is boiled down to a single
67	 * representative entry, this enum is passed-in to specify how that representative entry should be
68	 * calculated */
69	enum e_representative_entry_method {
70	    FIRST = 0, //the first cost that was recorded
71	    SMALLEST,  //the smallest-delay cost recorded
72	    AVERAGE,
73	    GEOMEAN,
74	    MEDIAN
75	};
