77	/**
78	 * @brief f_cost_map is an array of these cost entries that specifies delay/congestion estimates to travel relative x/y distances
79	 */
80	class Cost_Entry {
81	  public:
82	    float delay;      ///<Delay value of the cost entry
83	    float congestion; ///<Base cost value of the cost entry
84	    bool fill;        ///<Boolean specifying whether this Entry was created as a result of the cost map
85	                      ///<holes filling procedure
86	
87	    Cost_Entry()
88	        : delay(std::numeric_limits<float>::quiet_NaN())
89	        , congestion(std::numeric_limits<float>::quiet_NaN())
90	        , fill(false) {}
91	    Cost_Entry(float set_delay, float set_congestion)
92	        : delay(set_delay)
93	        , congestion(set_congestion)
94	        , fill(false) {}
95	    Cost_Entry(float set_delay, float set_congestion, bool set_fill)
96	        : delay(set_delay)
97	        , congestion(set_congestion)
98	        , fill(set_fill) {}
99	    bool valid() const {
100	        return !(std::isnan(delay) || std::isnan(congestion));
101	    }
102	
103	    bool operator==(const Cost_Entry& other) const {
104	        return delay == other.delay && congestion == other.congestion;
105	    }
106	};
