108	/**
109	 * @brief a class that stores delay/congestion information for a given relative coordinate during the Dijkstra expansion.
110	 *
111	 * Since it stores multiple cost entries, it is later boiled down to a single representative cost entry to be stored
112	 * in the final lookahead cost map
113	 *
114	 * This class is used for the lookahead map implementation only
115	 */
116	class Expansion_Cost_Entry {
117	  private:
118	    std::vector<Cost_Entry> cost_vector; ///<This vector is used to store different cost entries that are treated
119	                                         ///<differently based on the below representative cost entry method computations
120	                                         ///<Currently, only the smallest entry is stored in the vector, but this prepares
121	                                         ///<the ground for other possible representative cost entry calculation methods.
122	                                         ///<The vector is filled for a specific (chan_index, segment_index, delta_x, delta_y) cost entry.
123	
124	    Cost_Entry get_smallest_entry() const;
125	    Cost_Entry get_average_entry() const;
126	    Cost_Entry get_geomean_entry() const;
127	    Cost_Entry get_median_entry() const;
128	
129	  public:
130	    void add_cost_entry(e_representative_entry_method method,
131	                        float add_delay,
132	                        float add_congestion) {
133	        Cost_Entry cost_entry(add_delay, add_congestion);
134	        if (method == SMALLEST) {
135	            /* taking the smallest-delay entry anyway, so no need to push back multiple entries */
136	            if (this->cost_vector.empty()) {
137	                this->cost_vector.push_back(cost_entry);
138	            } else {
139	                if (add_delay < this->cost_vector[0].delay) {
140	                    this->cost_vector[0] = cost_entry;
141	                }
142	            }
143	        } else {
144	            this->cost_vector.push_back(cost_entry);
145	        }
146	    }
147	    void clear_cost_entries() {
148	        this->cost_vector.clear();
149	    }
150	
151	    Cost_Entry get_representative_cost_entry(e_representative_entry_method method) const {
152	        Cost_Entry entry;
153	
154	        if (!cost_vector.empty()) {
155	            switch (method) {
156	                case FIRST:
157	                    entry = cost_vector[0];
158	                    break;
159	                case SMALLEST:
160	                    entry = this->get_smallest_entry();
161	                    break;
162	                case AVERAGE:
163	                    entry = this->get_average_entry();
164	                    break;
165	                case GEOMEAN:
166	                    entry = this->get_geomean_entry();
167	                    break;
168	                case MEDIAN:
169	                    entry = this->get_median_entry();
170	                    break;
171	                default:
172	                    break;
173	            }
174	        }
175	        return entry;
176	    }
177	};
